// MARK: - Keychain Helper for Secure Storage

final class KeychainManager {
    
    enum KeychainError: Error {
        case duplicateEntry
        case unknown(OSStatus)
        case itemNotFound
        case encodingError
    }
    
    static let shared = KeychainManager()
    private init() {}
    
    private let service = "com.app.biometricauth"
    private let authKey = "biometric_authenticated"
    private let tokenKey = "auth_session_token"
    
    func setBiometricAuthEnabled(_ enabled: Bool) throws {
        let data = Data(enabled ? [1] : [0])
        try save(key: authKey, data: data)
    }
    
    func isBiometricAuthEnabled() -> Bool {
        guard let data = try? load(key: authKey), let firstByte = data.first else {
            return false
        }
        return firstByte == 1
    }
    
    func saveSessionToken(_ token: String) throws {
        guard let data = token.data(using: .utf8) else {
            throw KeychainError.encodingError
        }
        try save(key: tokenKey, data: data, requireBiometric: true)
    }
    
    func loadSessionToken() throws -> String? {
        guard let data = try? load(key: tokenKey) else {
            return nil
        }
        return String(data: data, encoding: .utf8)
    }
    
    func clearAll() {
        delete(key: authKey)
        delete(key: tokenKey)
    }
    
    // MARK: - Private Keychain Operations
    
    private func save(key: String, data: Data, requireBiometric: Bool = false) throws {
        delete(key: key)
        
        var query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecValueData as String: data
        ]
        
        if requireBiometric {
            let access = SecAccessControlCreateWithFlags(
                nil,
                kSecAttrAccessibleWhenPasscodeSetThisDeviceOnly,
                .biometryCurrentSet,
                nil
            )
            if let access = access {
                query[kSecAttrAccessControl as String] = access
            }
        } else {
            query[kSecAttrAccessible as String] = kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        }
        
        let status = SecItemAdd(query as CFDictionary, nil)
        
        guard status == errSecSuccess else {
            throw KeychainError.unknown(status)
        }
    }
    
    private func load(key: String) throws -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]
        
        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)
        
        if status == errSecItemNotFound {
            return nil
        }
        
        guard status == errSecSuccess else {
            throw KeychainError.unknown(status)
        }
        
        return result as? Data
    }
    
    private func delete(key: String) {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrService as String: service,
            kSecAttrAccount as String: key
        ]
        SecItemDelete(query as CFDictionary)
    }
}

// MARK: - Biometric Authentication Manager

final class BiometricAuthManager {
    
    enum BiometricType {
        case none
        case touchID
        case faceID
    }
    
    enum AuthResult {
        case success
        case failure(Error)
        case biometryNotAvailable
        case biometryNotEnrolled
        case biometryLockout
        case userCancelled
        case fallbackRequested
    }
    
    static let shared = BiometricAuthManager()
    private init() {}
    
    private let keychainManager = KeychainManager.shared
    
    // Track authentication state in memory (not persisted insecurely)
    private(set) var isSessionAuthenticated = false
    private var sessionExpirationDate: Date?
    private let sessionDuration: TimeInterval = 300 // 5 minutes
    
    var biometricType: BiometricType {
        let context = LAContext()
        var error: NSError?
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            return .none
        }
        switch context.biometryType {
        case .touchID:
            return .touchID
        case .faceID:
            return .faceID
        case .opticID:
            return .faceID // Treat opticID similarly
        @unknown default:
            return .none
        }
    }
    
    var biometricDisplayName: String {
        switch biometricType {
        case .faceID: return "Face ID"
        case .touchID: return "Touch ID"
        case .none: return "Biometric Authentication"
        }
    }
    
    var isBiometricAvailable: Bool {
        let context = LAContext()
        var error: NSError?
        return context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error)
    }
    
    var isBiometricAuthEnabled: Bool {
        return keychainManager.isBiometricAuthEnabled()
    }
    
    var hasValidSession: Bool {
        guard isSessionAuthenticated,
              let expiration = sessionExpirationDate else {
            return false
        }
        return Date() < expiration
    }
    
    // MARK: - Enable/Disable Biometric Auth
    
    func enableBiometricAuth(sessionToken: String, completion: @escaping (AuthResult) -> Void) {
        authenticate(reason: "Authenticate to enable \(biometricDisplayName)") { [weak self] result in
            guard let self = self else { return }
            switch result {
            case .success:
                do {
                    try self.keychainManager.saveSessionToken(sessionToken)
                    try self.keychainManager.setBiometricAuthEnabled(true)
                    completion(.success)
                } catch {
                    completion(.failure(error))
                }
            default:
                completion(result)
            }
        }
    }
    
    func disableBiometricAuth() {
        keychainManager.clearAll()
        invalidateSession()
    }
    
    // MARK: - Authentication
    
    func authenticate(reason: String? = nil, completion: @escaping (AuthResult) -> Void) {
        let context = LAContext()
        context.localizedCancelTitle = "Use Password"
        context.localizedFallbackTitle = "Enter Password"
        
        // Invalidate previous context
        context.invalidate()
        
        let newContext = LAContext()
        newContext.localizedCancelTitle = "Use Password"
        newContext.localizedFallbackTitle = "Enter Password"
        
        var error: NSError?
        
        guard newContext.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: &error) else {
            if let error = error {
                let result = mapLAError(error)
                DispatchQueue.main.async {
                    completion(result)
                }
            } else {
                DispatchQueue.main.async {
                    completion(.biometryNotAvailable)
                }
            }
            return
        }
        
        let authReason = reason ?? "Authenticate with \(biometricDisplayName) to access your account"
        
        newContext.evaluatePolicy(
            .deviceOwnerAuthenticationWithBiometrics,
            localizedReason: authReason
        ) { [weak self] success, error in
            DispatchQueue.main.async {
                if success {
                    self?.establishSession()
                    completion(.success)
                } else if let error = error {
                    let result = self?.mapLAError(error as NSError) ?? .failure(error)
                    completion(result)
                } else {
                    completion(.failure(NSError(domain: "BiometricAuth", code: -1, userInfo: [NSLocalizedDescriptionKey: "Unknown error"])))
                }
            }
        }
    }
    
    func authenticateAndRetrieveToken(completion: @escaping (Result<String, Error>) -> Void) {
        authenticate { [weak self] result in
            switch result {
            case .success:
                do {
                    if let token = try self?.keychainManager.loadSessionToken() {
                        completion(.success(token))
                    } else {
                        completion(.failure(NSError(domain: "BiometricAuth", code: -2, userInfo: [NSLocalizedDescriptionKey: "No stored session token found"])))
                    }
                } catch {
                    completion(.failure(error))
                }
            case .failure(let error):
                completion(.failure(error))
            case .userCancelled:
                completion(.failure(NSError(domain: "BiometricAuth", code: -3, userInfo: [NSLocalizedDescriptionKey: "User cancelled"])))
            case .fallbackRequested:
                completion(.failure(NSError(domain: "BiometricAuth", code: -4, userInfo: [NSLocalizedDescriptionKey: "Fallback requested"])))
            case .biometryNotAvailable, .biometryNotEnrolled, .biometryLockout:
                completion(.failure(NSError(domain: "BiometricAuth", code: -5, userInfo: [NSLocalizedDescriptionKey: "Biometry unavailable"])))
            }
        }
    }
    
    // MARK: - Session Management
    
    func establishSession() {
        isSessionAuthenticated = true
        sessionExpirationDate = Date().addingTimeInterval(sessionDuration)
    }
    
    func invalidateSession() {
        isSessionAuthenticated = false
        sessionExpirationDate = nil
    }
    
    // MARK: - Private Helpers
    
    private func mapLAError(_ error: NSError) -> AuthResult {
        guard let laError = LAError.Code(rawValue: error.code) else {
            return .failure(error)
        }
        switch laError {
        case .authenticationFailed:
            return .failure(error)
        case .userCancel:
            return .userCancelled
        case .userFallback:
            return .fallbackRequested
        case .biometryNotAvailable:
            return .biometryNotAvailable
        case .biometryNotEnrolled:
            return .biometryNotEnrolled
        case .biometryLockout:
            return .biometryLockout
        case .systemCancel, .appCancel:
            return .userCancelled
        case .passcodeNotSet:
            return .biometryNotAvailable
        default:
            return .failure(error)
        }
    }
}

// MARK: - Authentication Coordinator

final class AuthenticationCoordinator {
    
    private let biometricManager = BiometricAuthManager.shared
    private weak var navigationController: UINavigationController?
    
    init(navigationController: UINavigationController) {
        self.navigationController = navigationController
    }
    
    func start() {
        if biometricManager.isBiometricAuthEnabled && biometricManager.isBiometricAvailable {
            attemptBiometricLogin()
        } else {
            showLoginScreen()
        }
    }
    
    private func attemptBiometricLogin() {
        biometricManager.authenticateAndRetrieveToken { [weak self] result in
            switch result {
            case .success(let token):
                self?.proceedToMainApp(with: token)
            case .failure:
                self?.showLoginScreen(withBiometricRetry: true)
            }
        }
    }
    
    private func showLoginScreen(withBiometricRetry: Bool = false) {
        let loginVC = LoginViewController()
        loginVC.delegate = self
        loginVC.showBiometricButton = withBiometricRetry && biometricManager.isBiometricAvailable
        navigationController?.setViewControllers([loginVC], animated: false)
    }
    
    private func proceedToMainApp(with token: String) {
        let mainVC = MainViewController()
        mainVC.sessionToken = token
        navigationController?.setViewControllers([mainVC], animated: true)
    }
}

extension AuthenticationCoordinator: LoginViewControllerDelegate {
    func loginViewControllerDidLogin(_ controller: LoginViewController, token: String) {
        if biometricManager.isBiometricAvailable && !biometricManager.isBiometricAuthEnabled {
            promptToEnableBiometric(token: token, from: controller)
        } else {
            proceedToMainApp(with: token)
        }
    }
    
    func loginViewControllerDidRequestBiometric(_ controller: LoginViewController) {
        attemptBiometricLogin()
    }
    
    private func promptToEnableBiometric(token: String, from controller: UIViewController) {
        let biometricName = biometricManager.biometricDisplayName
        let alert = UIAlertController(
            title: "Enable \(biometricName)?",
            message: "Would you like to use \(biometricName) to sign in next time?",
            preferredStyle: .alert
        )
        
        alert.addAction(UIAlertAction(title: "Enable", style: .default) { [weak self] _ in
            self?.biometricManager.enableBiometricAuth(sessionToken: token) { [weak self] result in
                switch result {
                case .success:
                    self?.proceedToMainApp(with: token)
                default:
                    // Even if biometric enrollment fails, proceed to main app
                    self?.proceedToMainApp(with: token)
                }
            }
        })
        
        alert.addAction(UIAlertAction(title: "Not Now", style: .cancel) { [weak self] _ in
            self?.proceedToMainApp(with: token)
        })
        
        controller.present(alert, animated: true)
    }
}

