final class MainViewController: UIViewController {
    
    var sessionToken: String?
    
    private let welcomeLabel: UILabel = {
        let label = UILabel()
        label.text = "Welcome! You're authenticated."
        label.font = .systemFont(ofSize: 22, weight: .semibold)
        label.textAlignment = .center
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let biometricToggleLabel: UILabel = {
        let label = UILabel()
        label.font = .systemFont(ofSize: 17)
        label.translatesAutoresizingMaskIntoConstraints = false
        return label
    }()
    
    private let biometricToggle: UISwitch = {
        let toggle = UISwitch()
        toggle.translatesAutoresizingMaskIntoConstraints = false
        return toggle
    }()
    
    private let logoutButton: UIButton = {
        let button = UIButton(type: .system)
        button.setTitle("Sign Out", for: .normal)
        button.setTitleColor(.systemRed, for: .normal)
        button.translatesAutoresizingMaskIntoConstraints = false
        return button
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        setupUI()
        
        let biometricName = BiometricAuthManager.shared.biometricDisplayName
        biometricToggleLabel.text = "Enable \(biometricName)"
        biometricToggle.isOn = BiometricAuthManager.shared.isBiometricAuthEnabled
        biometricToggle.isEnabled = BiometricAuthManager.shared.isBiometricAvailable
        
        biometricToggle.addTarget(self, action: #selector(biometricToggleChanged), for: .valueChanged)
        logoutButton.addTarget(self, action: #selector(logoutTapped), for: .touchUpInside)
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        navigationItem.hidesBackButton = true
        
        let toggleStack = UIStackView(arrangedSubviews: [biometricToggleLabel, biometricToggle])
        toggleStack.axis = .horizontal
        toggleStack.spacing = 12
        toggleStack.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(welcomeLabel)
        view.addSubview(toggleStack)
        view.addSubview(logoutButton)
        
        NSLayoutConstraint.activate([
            welcomeLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            welcomeLabel.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 80),
            welcomeLabel.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 32),
            welcomeLabel.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -32),
            
            toggleStack.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            toggleStack.topAnchor.constraint(equalTo: welcomeLabel.bottomAnchor, constant: 40),
            
            logoutButton.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            logoutButton.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor, constant: -40)
        ])
    }
    
    @objc private func biometricToggleChanged(_ sender: UISwitch) {
        if sender.isOn {
            guard let token = sessionToken else {
                sender.setOn(false, animated: true)
                return
            }
            BiometricAuthManager.shared.enableBiometricAuth(sessionToken: token) { [weak self] result in
                switch result {
                case .success:
                    break // Toggle stays on
                default:
                    sender.setOn(false, animated: true)
                    let alert = UIAlertController(
                        title: "Error",
                        message: "Could not enable biometric authentication. Please try again.",
                        preferredStyle: .alert
                    )
                    alert.addAction(UIAlertAction(title: "OK", style: .default))
                    self?.present(alert, animated: true)
                }
            }
        } else {
            BiometricAuthManager.shared.disableBiometricAuth()
        }
    }
    
    @objc private func logoutTapped() {
        BiometricAuthManager.shared.invalidateSession()
        // Navigate back to login
        let loginVC = LoginViewController()
        loginVC.showBiometricButton = BiometricAuthManager.shared.isBiometricAuthEnabled && BiometricAuthManager.shared.isBiometricAvailable
        navigationController?.setViewControllers([loginVC], animated: true)
    }
}

