    private let window: UIWindow
    private let navigationController: UINavigationController
    private var authCoordinator: AuthenticationCoordinator?
    
    init(window: UIWindow) {
        self.window = window
        self.navigationController = UINavigationController()
        self.navigationController.isNavigationBarHidden = true
    }
    
    func start() {
        window.rootViewController = navigationController
        window.makeKeyAndVisible()
        
        authCoordinator = AuthenticationCoordinator(navigationController: navigationController)
        authCoordinator?.start()
    }
    
    /// Call this when app enters background to invalidate session if needed
    func handleAppDidEnterBackground() {
        // Optionally invalidate session on background
        // BiometricAuthManager.shared.invalidateSession()
    }
    
    /// Call this when app becomes active to re-authenticate if session expired
    func handleAppDidBecomeActive() {
        if BiometricAuthManager.shared.isBiometricAuthEnabled &&
            !BiometricAuthManager.shared.hasValidSession {
            authCoordinator?.start()
        }
    }
}

